class Solution:
    def minAnagramLength(self, s: str) -> int:
        from collections import Counter

        n = len(s)
        total_count = Counter(s)

        # The minimum length of t must be a divisor of n
        # We check all possible divisors of n in increasing order
        for length in range(1, n + 1):
            if n % length != 0:
                continue
            # Check if the total count can be divided into n / length groups
            # Each group must have the same character count
            valid = True
            for count in total_count.values():
                if count % (n // length) != 0:
                    valid = False
                    break
            if valid:
                return length
        return n
